def _write(rel, gz_b64_str):
    """Decode gzipped+b64 payload and write to disk."""
    import gzip
    data = gzip.decompress(base64.b64decode("".join(gz_b64_str)))
    dst = ROOT / rel
    dst.parent.mkdir(parents=True, exist_ok=True)
    dst.write_bytes(data)
